'use client';

import React, { useState } from 'react';
import { useOS, Note, Task, Goal, Bookmark } from '../../context/OSContext';
import { 
  FileText, 
  CheckSquare, 
  Target, 
  Bookmark as BookmarkIcon, 
  Folder, 
  HardDrive, 
  Plus, 
  Trash2, 
  Pin, 
  ChevronRight, 
  Calendar, 
  PlusCircle, 
  Check, 
  Clock, 
  X,
  FileSpreadsheet
} from 'lucide-react';

interface DriveFile {
  name: string;
  type: 'folder' | 'pdf' | 'spreadsheet' | 'doc';
  content?: string;
  size?: string;
  children?: DriveFile[];
}

export const WorkspaceApp: React.FC = () => {
  const { 
    notes, addNote, updateNote, deleteNote, togglePinNote,
    tasks, addTask, toggleTask, deleteTask,
    goals, addGoal, updateGoalStatus, deleteGoal,
    bookmarks, addBookmark, deleteBookmark
  } = useOS();

  const [activeWorkspaceTab, setActiveWorkspaceTab] = useState<'notes' | 'tasks' | 'goals' | 'drive' | 'bookmarks'>('notes');

  // Notes state
  const [selectedNoteId, setSelectedNoteId] = useState<string | null>(notes[0]?.id || null);
  const selectedNote = notes.find(n => n.id === selectedNoteId);

  // New item inputs
  const [newNoteTitle, setNewNoteTitle] = useState('');
  const [newNoteContent, setNewNoteContent] = useState('');
  
  const [newTaskText, setNewTaskText] = useState('');
  
  const [newGoalTitle, setNewGoalTitle] = useState('');
  const [newGoalDeadline, setNewGoalDeadline] = useState('');

  const [newBmkName, setNewBmkName] = useState('');
  const [newBmkUrl, setNewBmkUrl] = useState('');
  const [newBmkCat, setNewBmkCat] = useState('Advertising');

  // Drive state
  const [drivePath, setDrivePath] = useState<string[]>([]); // Folder path stack
  const [selectedPreviewFile, setSelectedPreviewFile] = useState<{ name: string; type: string; content: string } | null>(null);

  const driveRoot: DriveFile[] = [
    {
      name: 'Client Materials',
      type: 'folder',
      children: [
        { name: 'WayneCorp_SEO_Brief.doc', type: 'doc', content: 'WAYNE ENTERPRISES - SECRET R&D BRIEF\n\nGoals: Optimize stealth search terms for the new electric hyper-tank launch.\nKeywords: "Wayne EV armored car Bangalore", "unmanned electric vehicles pricing"\nAd Budget: Undisclosed.\nTimeline: Q3 2026.', size: '48 KB' },
        { name: 'Skynet_ROAS_Q1.spreadsheet', type: 'spreadsheet', content: 'SKYNET E-COMMERCE ROAS REPORT Q1 2026\n\nAd Spend: $40,000\nTotal Revenue: $212,000\nConversions: 4,200 purchases\nROAS: 5.3x\nCTR: 3.14%\nTop Creatives: Video hooks showing machine vision cameras.', size: '120 KB' }
      ]
    },
    {
      name: 'Ad Reports',
      type: 'folder',
      children: [
        { name: 'MetaAds_Consolidation_Playbook.pdf', type: 'pdf', content: 'META ADS ADVANTAGE+ CONSOLIDATION GUIDE\n\nRule 1: Stop setting up multiple parallel micro-targeted ad sets. Use Broad targeting with demographic filters.\nRule 2: Let dynamic creative testing optimize copies.\nRule 3: Ensure pixel has 50 weekly events for high-level conversion optimization.', size: '240 KB' }
      ]
    },
    {
      name: 'Certificates',
      type: 'folder',
      children: [
        { name: 'Google_Ads_Search_Certified.pdf', type: 'pdf', content: 'CERTIFICATE OF ACHIEVEMENT\n\nGoogle certifies that Manoj Kumar has successfully passed the Google Ads Search Assessment.\nLicense: #9938210\nValid: July 2026 - July 2027.', size: '320 KB' }
      ]
    }
  ];

  const getActiveDriveDirectory = (): DriveFile[] => {
    let currentDir = driveRoot;
    for (const folderName of drivePath) {
      const folder = currentDir.find(item => item.name === folderName && item.type === 'folder');
      if (folder && folder.children) {
        currentDir = folder.children;
      }
    }
    return currentDir;
  };

  const handleFolderClick = (file: DriveFile) => {
    if (file.type === 'folder') {
      setDrivePath(prev => [...prev, file.name]);
    } else {
      setSelectedPreviewFile({
        name: file.name,
        type: file.type,
        content: file.content || ''
      });
    }
  };

  const handleDriveBack = () => {
    setDrivePath(prev => prev.slice(0, -1));
  };

  return (
    <div className="flex-grow flex overflow-hidden h-full">
      {/* Workspace Menu list */}
      <div className="w-44 border-r border-white/5 bg-black/30 flex flex-col p-4 gap-1.5 shrink-0 select-none">
        <label className="text-[9px] text-white/40 uppercase tracking-widest font-extrabold mb-2 px-2">Workspace Apps</label>
        {[
          { id: 'notes' as const, label: 'Notes Editor', icon: FileText, color: 'text-amber-400' },
          { id: 'tasks' as const, label: 'Tasks Board', icon: CheckSquare, color: 'text-emerald-400' },
          { id: 'goals' as const, label: 'Goals Calendar', icon: Target, color: 'text-cyan-400' },
          { id: 'drive' as const, label: 'Google Drive Vault', icon: HardDrive, color: 'text-purple-400' },
          { id: 'bookmarks' as const, label: 'Bookmarks Linker', icon: BookmarkIcon, color: 'text-pink-400' }
        ].map(tab => {
          const Icon = tab.icon;
          return (
            <button
              key={tab.id}
              onClick={() => setActiveWorkspaceTab(tab.id)}
              className={`w-full text-left px-3 py-1.5 rounded-lg text-xs font-semibold flex items-center gap-2.5 transition-all ${
                activeWorkspaceTab === tab.id 
                  ? 'bg-white/10 text-white font-bold' 
                  : 'text-slate-400 hover:bg-white/5'
              }`}
            >
              <Icon className={`w-4 h-4 ${tab.color}`} />
              {tab.label}
            </button>
          );
        })}
      </div>

      {/* Tools Content Pane */}
      <div className="flex-grow overflow-hidden flex flex-col p-6 bg-slate-950/15">
        
        {/* APP 1: NOTES EDITOR */}
        {activeWorkspaceTab === 'notes' && (
          <div className="flex-1 flex overflow-hidden gap-4">
            {/* Notes List */}
            <div className="w-56 border-r border-white/5 pr-4 flex flex-col gap-2 overflow-y-auto select-none shrink-0">
              <div className="flex justify-between items-center mb-1">
                <span className="text-[10px] text-white/50 font-bold uppercase">My Notes</span>
                <button 
                  onClick={() => {
                    addNote('New Strategy Draft', 'Start writing marketing outlines...');
                    // Auto select the new note if we can find its ID (we will select it later)
                  }}
                  className="p-1 rounded bg-white/5 hover:bg-cyan-500/20 text-cyan-400 border border-white/5 hover:border-cyan-500/30"
                >
                  <Plus className="w-3.5 h-3.5" />
                </button>
              </div>

              {notes.map(note => (
                <div 
                  key={note.id}
                  onClick={() => setSelectedNoteId(note.id)}
                  className={`p-2.5 rounded-lg cursor-pointer text-left transition-colors border ${
                    selectedNoteId === note.id 
                      ? 'bg-cyan-500/10 border-cyan-500/30 text-white font-semibold' 
                      : 'bg-white/5 border-white/5 text-slate-300 hover:bg-white/10'
                  }`}
                >
                  <div className="flex items-center justify-between gap-1.5 mb-1">
                    <span className="font-bold text-xs truncate flex-1">{note.title}</span>
                    {note.pinned && <Pin className="w-3 h-3 text-amber-400 shrink-0 fill-current" />}
                  </div>
                  <p className="text-[10px] text-slate-400 truncate leading-none">{note.content || 'Empty note'}</p>
                </div>
              ))}
            </div>

            {/* Note Editor area */}
            <div className="flex-grow flex flex-col justify-between overflow-hidden">
              {selectedNote ? (
                <div className="flex-1 flex flex-col gap-3 overflow-hidden">
                  <div className="flex justify-between items-center border-b border-white/5 pb-2">
                    <input 
                      type="text"
                      value={selectedNote.title}
                      onChange={(e) => updateNote(selectedNote.id, e.target.value, selectedNote.content)}
                      className="bg-transparent text-sm font-bold text-white outline-none border-b border-transparent focus:border-white/15 w-full mr-4"
                    />
                    <div className="flex gap-1.5 select-none shrink-0">
                      <button 
                        onClick={() => togglePinNote(selectedNote.id)}
                        className={`p-1.5 rounded bg-white/5 hover:bg-white/10 ${selectedNote.pinned ? 'text-amber-400' : 'text-slate-400'}`}
                        title="Pin Note"
                      >
                        <Pin className="w-3.5 h-3.5" />
                      </button>
                      <button 
                        onClick={() => { deleteNote(selectedNote.id); setSelectedNoteId(notes.find(n => n.id !== selectedNote.id)?.id || null); }}
                        className="p-1.5 rounded bg-white/5 hover:bg-red-500/20 text-red-400 border border-white/5"
                        title="Delete Note"
                      >
                        <Trash2 className="w-3.5 h-3.5" />
                      </button>
                    </div>
                  </div>
                  
                  <textarea 
                    value={selectedNote.content}
                    onChange={(e) => updateNote(selectedNote.id, selectedNote.title, e.target.value)}
                    placeholder="Start drafting content ideas..."
                    className="flex-1 bg-transparent text-xs text-slate-300 leading-relaxed outline-none resize-none overflow-y-auto"
                  />
                </div>
              ) : (
                <div className="w-full h-full flex flex-col items-center justify-center text-slate-500 text-center select-none">
                  <FileText className="w-8 h-8 text-white/5 mb-1.5" />
                  <p className="text-xs">Create or select a note to start editing marketing material.</p>
                </div>
              )}
            </div>
          </div>
        )}

        {/* APP 2: TASKS BOARD */}
        {activeWorkspaceTab === 'tasks' && (
          <div className="flex-grow flex flex-col overflow-hidden max-w-xl mx-auto w-full">
            <h3 className="font-bold text-sm text-white mb-2">My Tasks Board</h3>
            
            {/* Input task */}
            <div className="flex gap-2 shrink-0 mb-4 select-none">
              <input 
                type="text"
                value={newTaskText}
                onChange={(e) => setNewTaskText(e.target.value)}
                onKeyDown={(e) => { if(e.key === 'Enter' && newTaskText.trim()) { addTask(newTaskText); setNewTaskText(''); } }}
                placeholder="Add a new checklist task (e.g. GTM pixels check)..."
                className="flex-grow glass-input px-3.5 py-2 text-xs"
              />
              <button 
                onClick={() => { if(newTaskText.trim()) { addTask(newTaskText); setNewTaskText(''); } }}
                className="px-4 py-2 bg-cyan-500 hover:bg-cyan-400 text-slate-950 font-bold rounded-lg flex items-center justify-center cursor-pointer text-xs"
              >
                Add Task
              </button>
            </div>

            {/* Task list list */}
            <div className="flex-grow overflow-y-auto flex flex-col gap-2">
              {tasks.length > 0 ? (
                tasks.map(task => (
                  <div 
                    key={task.id} 
                    className={`p-3 bg-white/5 border border-white/5 rounded-xl flex items-center justify-between hover:bg-white/10 transition-colors ${
                      task.completed ? 'opacity-55' : ''
                    }`}
                  >
                    <div 
                      onClick={() => toggleTask(task.id)}
                      className="flex items-center gap-3 cursor-pointer flex-grow text-left text-xs"
                    >
                      <span className={`w-4 h-4 rounded-full border flex items-center justify-center shrink-0 ${
                        task.completed 
                          ? 'border-emerald-400 bg-emerald-500/25 text-emerald-400' 
                          : 'border-white/30'
                      }`}>
                        {task.completed && <Check className="w-3 h-3 stroke-[3]" />}
                      </span>
                      <span className={`font-semibold text-white/90 ${task.completed ? 'line-through text-slate-500' : ''}`}>
                        {task.text}
                      </span>
                    </div>

                    <button 
                      onClick={() => deleteTask(task.id)}
                      className="p-1 rounded text-slate-500 hover:text-red-400 select-none hover:bg-white/5 transition-colors"
                    >
                      <Trash2 className="w-3.5 h-3.5" />
                    </button>
                  </div>
                ))
              ) : (
                <div className="w-full h-full flex flex-col items-center justify-center text-slate-500 text-center select-none py-12">
                  <CheckSquare className="w-8 h-8 text-white/5 mb-1.5" />
                  <p className="text-xs">No tasks active. Create a task checklist!</p>
                </div>
              )}
            </div>
          </div>
        )}

        {/* APP 3: GOALS BOARD */}
        {activeWorkspaceTab === 'goals' && (
          <div className="flex-1 flex flex-col overflow-hidden max-w-2xl mx-auto w-full">
            <h3 className="font-bold text-sm text-white mb-2">Campaign Goals Board</h3>
            
            {/* Input goal */}
            <div className="grid grid-cols-3 gap-2 shrink-0 mb-4 select-none bg-white/5 border border-white/5 p-3 rounded-xl">
              <div className="flex flex-col gap-1 col-span-2">
                <input 
                  type="text"
                  value={newGoalTitle}
                  onChange={(e) => setNewGoalTitle(e.target.value)}
                  placeholder="Target CPA under $12, increase traffic..."
                  className="glass-input px-3 py-1.5 text-xs"
                />
              </div>
              <div className="flex flex-col gap-1">
                <input 
                  type="date"
                  value={newGoalDeadline}
                  onChange={(e) => setNewGoalDeadline(e.target.value)}
                  className="glass-input px-3 py-1.5 text-xs text-white"
                />
              </div>
              <button 
                onClick={() => { if(newGoalTitle.trim()) { addGoal(newGoalTitle, newGoalDeadline); setNewGoalTitle(''); setNewGoalDeadline(''); } }}
                className="col-span-3 py-1.5 bg-cyan-500 hover:bg-cyan-400 text-slate-950 font-bold rounded-lg text-xs"
              >
                Define Growth Goal
              </button>
            </div>

            {/* Goals list */}
            <div className="flex-grow overflow-y-auto flex flex-col gap-2.5">
              {goals.length > 0 ? (
                goals.map(goal => (
                  <div 
                    key={goal.id} 
                    className="p-3 bg-white/5 border border-white/5 rounded-xl flex items-center justify-between text-xs"
                  >
                    <div className="flex flex-col text-left">
                      <span className="font-bold text-white leading-tight mb-1">{goal.title}</span>
                      <span className="text-[10px] text-slate-400 flex items-center gap-1">
                        <Calendar className="w-3 h-3 text-cyan-400" /> Deadline: {goal.deadline}
                      </span>
                    </div>

                    <div className="flex items-center gap-3 select-none">
                      <select 
                        value={goal.status} 
                        onChange={(e) => updateGoalStatus(goal.id, e.target.value as 'pending' | 'in-progress' | 'completed')}
                        className={`bg-white/5 border rounded px-2 py-0.5 text-[10px] font-bold uppercase outline-none cursor-pointer ${
                          goal.status === 'completed' 
                            ? 'text-emerald-400 border-emerald-500/30' 
                            : goal.status === 'in-progress' 
                              ? 'text-yellow-400 border-yellow-500/30' 
                              : 'text-cyan-400 border-cyan-500/30'
                        }`}
                      >
                        <option value="pending" className="bg-slate-900 text-cyan-400">Pending</option>
                        <option value="in-progress" className="bg-slate-900 text-yellow-400">In Progress</option>
                        <option value="completed" className="bg-slate-900 text-emerald-400">Completed</option>
                      </select>

                      <button 
                        onClick={() => deleteGoal(goal.id)}
                        className="p-1 rounded text-slate-500 hover:text-red-400"
                      >
                        <Trash2 className="w-3.5 h-3.5" />
                      </button>
                    </div>
                  </div>
                ))
              ) : (
                <div className="w-full h-full flex flex-col items-center justify-center text-slate-500 text-center select-none py-12">
                  <Target className="w-8 h-8 text-white/5 mb-1.5" />
                  <p className="text-xs">No active business goals defined yet.</p>
                </div>
              )}
            </div>
          </div>
        )}

        {/* APP 4: GOOGLE DRIVE VAULT */}
        {activeWorkspaceTab === 'drive' && (
          <div className="flex-1 flex flex-col overflow-hidden">
            {/* Folder Navigation Bar */}
            <div className="flex items-center gap-2 border-b border-white/5 pb-2.5 mb-4 shrink-0 select-none">
              <button 
                onClick={() => setDrivePath([])}
                className="text-[10px] font-bold text-cyan-400 hover:underline uppercase tracking-wider flex items-center gap-1"
              >
                <HardDrive className="w-3.5 h-3.5 text-cyan-400" /> My Drive
              </button>
              
              {drivePath.map((folder, index) => (
                <React.Fragment key={index}>
                  <ChevronRight className="w-3.5 h-3.5 text-slate-500" />
                  <button 
                    onClick={() => setDrivePath(drivePath.slice(0, index + 1))}
                    className="text-[10px] font-semibold text-white/80 hover:text-white"
                  >
                    {folder}
                  </button>
                </React.Fragment>
              ))}

              {drivePath.length > 0 && (
                <button 
                  onClick={handleDriveBack}
                  className="ml-auto glass-button px-2.5 py-0.5 text-[9px] font-bold flex items-center gap-1 text-slate-300"
                >
                  ← Back
                </button>
              )}
            </div>

            {/* Folder Grid Contents */}
            <div className="flex-grow overflow-y-auto grid grid-cols-2 sm:grid-cols-4 md:grid-cols-5 gap-3">
              {getActiveDriveDirectory().map((file, i) => (
                <div
                  key={i}
                  onDoubleClick={() => handleFolderClick(file)}
                  onClick={() => handleFolderClick(file)}
                  className="p-3 bg-white/5 border border-white/5 hover:border-cyan-500/25 rounded-xl flex flex-col items-center justify-between text-center cursor-pointer hover:bg-white/10 group select-none relative aspect-square"
                >
                  <div className="flex-grow flex items-center justify-center">
                    {file.type === 'folder' ? (
                      <Folder className="w-12 h-12 text-yellow-400 fill-current group-hover:scale-105 transition-transform" />
                    ) : file.type === 'spreadsheet' ? (
                      <FileSpreadsheet className="w-12 h-12 text-emerald-400 group-hover:scale-105 transition-transform" />
                    ) : (
                      <FileText className="w-12 h-12 text-blue-400 group-hover:scale-105 transition-transform" />
                    )}
                  </div>
                  <div className="w-full">
                    <p className="text-[10px] font-bold text-white/95 truncate w-full px-1">{file.name}</p>
                    {file.size && <span className="text-[8px] text-white/30">{file.size}</span>}
                  </div>
                </div>
              ))}
            </div>

            {/* Drive Preview Modal */}
            {selectedPreviewFile && (
              <div className="fixed inset-0 bg-black/80 z-50 flex items-center justify-center p-4">
                <div className="w-full max-w-lg glass-panel-heavy p-4 rounded-xl shadow-2xl border border-white/15 text-white flex flex-col justify-between max-h-[75vh]">
                  <div className="flex justify-between items-center border-b border-white/10 pb-2 mb-3">
                    <span className="font-bold text-xs flex items-center gap-1.5">
                      {selectedPreviewFile.type === 'spreadsheet' ? (
                        <FileSpreadsheet className="w-4 h-4 text-emerald-400" />
                      ) : (
                        <FileText className="w-4 h-4 text-blue-400" />
                      )}
                      {selectedPreviewFile.name}
                    </span>
                    <button 
                      onClick={() => setSelectedPreviewFile(null)}
                      className="p-1 rounded hover:bg-white/10 text-white/70"
                    >
                      <X className="w-4 h-4" />
                    </button>
                  </div>
                  
                  <div className="flex-1 overflow-y-auto bg-slate-950/40 p-4 border border-white/5 rounded-lg text-xs leading-relaxed font-mono whitespace-pre-wrap select-text selection:bg-cyan-500/30">
                    {selectedPreviewFile.content}
                  </div>
                  
                  <div className="flex gap-2 justify-end mt-3 border-t border-white/5 pt-2 select-none">
                    <button 
                      onClick={() => setSelectedPreviewFile(null)}
                      className="glass-button px-4 py-1.5 text-xs text-slate-300"
                    >
                      Close Preview
                    </button>
                  </div>
                </div>
              </div>
            )}
          </div>
        )}

        {/* APP 5: BOOKMARKS LINKER */}
        {activeWorkspaceTab === 'bookmarks' && (
          <div className="flex-1 flex overflow-hidden gap-6">
            {/* Form list adding */}
            <div className="w-64 border-r border-white/5 pr-6 flex flex-col gap-4 overflow-y-auto select-none shrink-0 text-left">
              <div>
                <h4 className="font-bold text-sm text-white">Save Bookmark</h4>
                <p className="text-[10px] text-slate-400">Keep handy quick links in the app Launcher</p>
              </div>

              <div className="flex flex-col gap-3">
                <div className="flex flex-col gap-1">
                  <label className="text-[10px] text-white/50">Link Name</label>
                  <input 
                    type="text" 
                    value={newBmkName}
                    onChange={(e) => setNewBmkName(e.target.value)}
                    placeholder="Semrush Audit, n8n..." 
                    className="glass-input px-3 py-1.5 text-xs" 
                  />
                </div>
                
                <div className="flex flex-col gap-1">
                  <label className="text-[10px] text-white/50">Link URL</label>
                  <input 
                    type="text" 
                    value={newBmkUrl}
                    onChange={(e) => setNewBmkUrl(e.target.value)}
                    placeholder="semrush.com/dashboard" 
                    className="glass-input px-3 py-1.5 text-xs" 
                  />
                </div>
                
                <div className="flex flex-col gap-1">
                  <label className="text-[10px] text-white/50">Category</label>
                  <select 
                    value={newBmkCat}
                    onChange={(e) => setNewBmkCat(e.target.value)}
                    className="bg-white/5 border border-white/10 rounded px-2.5 py-1.5 text-xs text-white outline-none cursor-pointer"
                  >
                    <option value="Advertising" className="bg-slate-900 text-white">Advertising</option>
                    <option value="Analytics" className="bg-slate-900 text-white">Analytics</option>
                    <option value="SEO Tools" className="bg-slate-900 text-white">SEO Tools</option>
                    <option value="General" className="bg-slate-900 text-white">General</option>
                  </select>
                </div>

                <button 
                  onClick={() => { if(newBmkName.trim() && newBmkUrl.trim()) { addBookmark(newBmkName, newBmkUrl, newBmkCat); setNewBmkName(''); setNewBmkUrl(''); } }}
                  className="w-full py-2 bg-cyan-500 hover:bg-cyan-400 text-slate-950 font-bold text-xs rounded-lg flex items-center justify-center gap-1"
                >
                  <PlusCircle className="w-3.5 h-3.5" /> Save Link
                </button>
              </div>
            </div>

            {/* Bookmarks Grid display */}
            <div className="flex-grow overflow-y-auto">
              <h4 className="font-bold text-xs text-white/50 uppercase tracking-widest mb-3 text-left select-none">Pinned Bookmarks</h4>
              <div className="grid grid-cols-2 gap-3">
                {bookmarks.map(bmk => (
                  <div 
                    key={bmk.id}
                    className="p-3 bg-white/5 border border-white/5 hover:border-cyan-500/20 rounded-xl flex items-center justify-between group shadow"
                  >
                    <a
                      href={bmk.url}
                      target="_blank"
                      rel="noreferrer"
                      className="flex-grow text-left text-xs text-slate-200 hover:text-white font-bold truncate mr-3"
                    >
                      <p className="leading-tight truncate">{bmk.name}</p>
                      <span className="text-[8px] text-cyan-400 bg-cyan-500/10 border border-cyan-500/20 px-1.5 py-0.5 rounded-full font-semibold uppercase tracking-wider mt-1 inline-block">
                        {bmk.category}
                      </span>
                    </a>
                    
                    <button 
                      onClick={() => deleteBookmark(bmk.id)}
                      className="p-1 rounded text-slate-500 hover:text-red-400 select-none opacity-0 group-hover:opacity-100 transition-opacity"
                    >
                      <Trash2 className="w-3.5 h-3.5" />
                    </button>
                  </div>
                ))}
              </div>
            </div>
          </div>
        )}

      </div>
    </div>
  );
};
