'use client';

import React, { useRef, useState, useEffect } from 'react';
import { useOS, OSWindow } from '../../context/OSContext';
import { Minimize2, Maximize2, X, Move, ExternalLink } from 'lucide-react';

interface WindowProps {
  windowState: OSWindow;
  children: React.ReactNode;
}

export const Window: React.FC<WindowProps> = ({ windowState, children }) => {
  const { 
    id, 
    title, 
    isOpen, 
    isMaximized, 
    isMinimized, 
    x, 
    y, 
    w, 
    h, 
    zIndex 
  } = windowState;

  const { 
    activeWindowId, 
    focusWindow, 
    openWindow,
    closeWindow, 
    minimizeWindow, 
    maximizeWindow,
    setWindows,
    theme
  } = useOS();

  const windowRef = useRef<HTMLDivElement>(null);
  const [isDragging, setIsDragging] = useState(false);
  const [isResizing, setIsResizing] = useState(false);
  
  // Drag state
  const [dragStart, setDragStart] = useState({ x: 0, y: 0 });
  const [windowPosStart, setWindowPosStart] = useState({ x: 0, y: 0 });
  
  // Resize state
  const [resizeStart, setResizeStart] = useState({ x: 0, y: 0 });
  const [windowSizeStart, setWindowSizeStart] = useState({ w: 0, h: 0 });

  // Focus window on click
  const handleWindowClick = () => {
    if (activeWindowId !== id) {
      focusWindow(id);
    }
  };

  // Dragging event handlers
  const handleDragStart = (e: React.MouseEvent) => {
    if (isMaximized) return;
    
    // Only drag from title bar, not buttons
    if ((e.target as HTMLElement).closest('.window-control-btn')) return;
    
    setIsDragging(true);
    setDragStart({ x: e.clientX, y: e.clientY });
    setWindowPosStart({ x, y });
    focusWindow(id);
    e.preventDefault();
  };

  // Resizing event handlers
  const handleResizeStart = (e: React.MouseEvent) => {
    if (isMaximized) return;
    
    setIsResizing(true);
    setResizeStart({ x: e.clientX, y: e.clientY });
    setWindowSizeStart({ w, h });
    focusWindow(id);
    e.preventDefault();
    e.stopPropagation();
  };

  // Global mousemove/mouseup listeners for dragging & resizing
  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (isDragging) {
        const dx = e.clientX - dragStart.x;
        const dy = e.clientY - dragStart.y;
        
        // Boundaries capping (keep window header on screen)
        const newX = Math.max(-w + 100, Math.min(window.innerWidth - 100, windowPosStart.x + dx));
        const newY = Math.max(0, Math.min(window.innerHeight - 50, windowPosStart.y + dy));

        setWindows(prev => prev.map(win => {
          if (win.id === id) {
            return { ...win, x: newX, y: newY };
          }
          return win;
        }));
      }

      if (isResizing) {
        const dx = e.clientX - resizeStart.x;
        const dy = e.clientY - resizeStart.y;

        const newW = Math.max(400, windowSizeStart.w + dx);
        const newH = Math.max(300, windowSizeStart.h + dy);

        setWindows(prev => prev.map(win => {
          if (win.id === id) {
            return { ...win, w: newW, h: newH };
          }
          return win;
        }));
      }
    };

    const handleMouseUp = () => {
      setIsDragging(false);
      setIsResizing(false);
    };

    if (isDragging || isResizing) {
      document.addEventListener('mousemove', handleMouseMove);
      document.addEventListener('mouseup', handleMouseUp);
    }

    return () => {
      document.removeEventListener('mousemove', handleMouseMove);
      document.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging, isResizing, dragStart, resizeStart, windowPosStart, windowSizeStart, w, h, id, isMaximized, setWindows]);

  if (!isOpen || isMinimized) return null;

  // Window styling based on theme
  const getWindowStyles = (): React.CSSProperties => {
    if (isMaximized) {
      return {
        position: 'absolute',
        left: 0,
        top: '32px', // below TopBar
        width: '100vw',
        height: 'calc(100vh - 96px)', // below TopBar & above Dock
        zIndex,
      };
    }

    return {
      position: 'absolute',
      left: `${x}px`,
      top: `${y}px`,
      width: `${w}px`,
      height: `${h}px`,
      zIndex,
    };
  };

  const isActive = activeWindowId === id;

  return (
    <div 
      ref={windowRef}
      style={getWindowStyles()}
      onClick={handleWindowClick}
      className={`glass-panel rounded-xl shadow-2xl overflow-hidden flex flex-col transition-shadow duration-300 border ${
        isActive 
          ? 'ring-1 ring-cyan-500/20 shadow-cyan-500/5 border-cyan-500/25' 
          : 'opacity-90 border-white/10'
      }`}
    >
      {/* Titlebar Header */}
      <div 
        onMouseDown={handleDragStart}
        onDoubleClick={() => maximizeWindow(id)}
        className="w-full h-10 px-4 flex items-center justify-between cursor-move select-none border-b border-white/5"
        style={{
          background: 'var(--window-header-bg)',
        }}
      >
        {/* Apple Style Traffic Light Controls */}
        <div className="flex items-center gap-1.5 w-20">
          <div 
            onClick={() => closeWindow(id)} 
            className="window-control-btn window-titlebar-btn btn-close"
            title="Close"
          />
          <div 
            onClick={() => minimizeWindow(id)} 
            className="window-control-btn window-titlebar-btn btn-min"
            title="Minimize"
          />
          <div 
            onClick={() => maximizeWindow(id)} 
            className="window-control-btn window-titlebar-btn btn-max"
            title="Maximize"
          />
        </div>

        {/* Title */}
        <div className="flex items-center gap-2 text-xs font-semibold tracking-wider text-white/95 glowing-text">
          <span className="opacity-80 capitalize">{title}</span>
        </div>

        {/* Window Options Menu */}
        <div className="flex items-center gap-3 text-white/40 w-20 justify-end select-none">
          <button 
            onClick={(e) => {
              e.stopPropagation();
              openWindow(id, 'popup');
              closeWindow(id);
            }}
            className="hover:text-white transition-colors cursor-pointer flex items-center justify-center p-0.5"
            title="Open as Standalone Popup"
          >
            <ExternalLink className="w-3.5 h-3.5 opacity-60 hover:opacity-100" />
          </button>
          <Move className="w-3.5 h-3.5 opacity-60" />
        </div>
      </div>

      {/* Main Window Body Content Container */}
      <div className="flex-1 overflow-hidden relative flex flex-col bg-[#050508]/65 text-slate-100">
        {children}
      </div>

      {/* Resizer Corner Handle */}
      {!isMaximized && (
        <div 
          onMouseDown={handleResizeStart}
          className="absolute bottom-0 right-0 w-4 h-4 cursor-se-resize z-50 flex items-end justify-end p-0.5"
        >
          <svg width="8" height="8" viewBox="0 0 8 8" className="opacity-40 text-white hover:opacity-100">
            <line x1="6" y1="0" x2="6" y2="6" stroke="currentColor" strokeWidth="1" />
            <line x1="0" y1="6" x2="6" y2="6" stroke="currentColor" strokeWidth="1" />
            <line x1="4" y1="2" x2="4" y2="4" stroke="currentColor" strokeWidth="1" />
            <line x1="2" y1="4" x2="4" y2="4" stroke="currentColor" strokeWidth="1" />
          </svg>
        </div>
      )}
    </div>
  );
};
